CREATE TRIGGER LG_ACCDISTLINE_INS_099_02 ON LG_099_02_ACCDISTDETLN
FOR INSERT
AS
DECLARE @DT     DATETIME
DECLARE @MONTH          SMALLINT
DECLARE @YEAR          SMALLINT
DECLARE @SIGN  SMALLINT
DECLARE @ACCFICHEREF    INT
DECLARE @ACCOUNTREF INT
DECLARE @CENTERREF      INT
DECLARE @TRCODE  SMALLINT
DECLARE @ACCOUNTCODE    VARCHAR(100)
DECLARE @DEBIT  FLOAT
DECLARE @CREDIT   FLOAT
DECLARE @EMUDEBIT       FLOAT
DECLARE @EMUCREDIT  FLOAT
DECLARE @CANCELLED SMALLINT
DECLARE @REPORTNET FLOAT
DECLARE @INFIDX         FLOAT
DECLARE @NOTINFLATED    INT
DECLARE @NOTCALCULATED  INT
DECLARE @AMNT  FLOAT
DECLARE @COEF  SMALLINT
DECLARE @BRANCH  SMALLINT
DECLARE @DEPARTMENT SMALLINT
DECLARE @STATUS  SMALLINT
DECLARE @TRNET          FLOAT
DECLARE @TRCURR         SMALLINT
SELECT @DT          = I.DATE_,
       @MONTH       = I.MONTH_,
       @YEAR        = I.YEAR_,
       @SIGN        = I.TSIGN,
       @ACCFICHEREF = I.ACCFICHEREF,
       @ACCOUNTREF  = 0,
       @CENTERREF   = I.CENTERREF,
       @TRCODE      = 0,
       @ACCOUNTCODE = '',
       @DEBIT       = (CASE I.TSIGN WHEN 0 THEN  I.CREDEBNET ELSE 0 END ),
       @CREDIT      = (CASE I.TSIGN WHEN 1 THEN  I.CREDEBNET ELSE 0 END ),
       @EMUDEBIT    = (CASE I.TSIGN WHEN 0 THEN  I.EMUCREDEBNET ELSE 0 END),
       @EMUCREDIT   = (CASE I.TSIGN WHEN 1 THEN  I.EMUCREDEBNET ELSE 0 END),
       @CANCELLED   = I.CANCELLED ,
       @REPORTNET   = I.REPORTNET,
       @INFIDX        = 0,
       @NOTINFLATED   = 0,
       @NOTCALCULATED = 0,
       @AMNT        = 0,
       @BRANCH      = I.BRANCH,
       @DEPARTMENT  = I.DEPARTMENT,
       @STATUS      = I.STATUS,
       @TRNET       = I.TRNET,
       @TRCURR      = I.TRCURR FROM INSERTED I
SELECT @TRCODE=TRCODE FROM LG_099_02_EMFICHE WHERE LOGICALREF=@ACCFICHEREF
EXECUTE LG_UPDATE_EMTRANS_099_02 @DT, @SIGN, @ACCOUNTREF, @CENTERREF, @TRCODE, @ACCOUNTCODE, @DEBIT, @CREDIT, @EMUDEBIT, @EMUCREDIT, @CANCELLED, @REPORTNET, @AMNT, 1
        , @INFIDX, @NOTINFLATED, @NOTCALCULATED, @BRANCH, @DEPARTMENT, @STATUS, 0, 0, 0
        , @MONTH, @YEAR, @TRNET, @TRCURR
